                if (!projectList) throw new Error("List 'Carsan_Projects' not found. Initialize Database first.");

                let successCount = 0;
                let failCount = 0;
                const total = jsonData.length;

                setStatusMsg(`Uploading ${total} projects...`);

                for (let i = 0; i < total; i++) {
