import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Login } from './components/Login';
import { ProjectList } from './components/ProjectList';
import { Estimator } from './components/Estimator';
import { PriceDatabase } from './components/PriceDatabase';
import { CRM } from './components/CRM';
import { ServiceModule } from './components/ServiceModule';
import { PriceAnalysis } from './components/PriceAnalysis';
import { AIAssistant } from './components/AIAssistant';
import { SharePointConnect } from './components/SharePointConnect';
import { ViewState, User, ProjectEstimate, MaterialItem, ServiceTicket, Lead, PurchaseRecord, AuditLog } from './types';
import { getAllPurchaseRecords } from './services/sharepointService';

const RESET_APP = false;

const loadState = <T,>(key: string, fallback: T): T => {
    if (RESET_APP) return fallback;
    const saved = localStorage.getItem(key);
    if (saved) { try { return JSON.parse(saved); } catch (e) { return fallback; } }
    return fallback;
};

export const App: React.FC = () => {
    useEffect(() => { console.log("Carsan Electric App v9.0 - CRM Restore"); }, []);

    const [user, setUser] = useState<User | null>(null);
    const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);

    const [projects, setProjects] = useState<ProjectEstimate[]>(() => loadState('carsan_projects', []));
    const [materials, setMaterials] = useState<MaterialItem[]>(() => loadState('carsan_materials', []));
    const [tickets, setTickets] = useState<ServiceTicket[]>(() => loadState('carsan_tickets', []));
    const [purchases, setPurchases] = useState<PurchaseRecord[]>(() => loadState('carsan_purchases', []));
    const [leads, setLeads] = useState<Lead[]>(() => loadState('carsan_leads', []));
    const [opportunities, setOpportunities] = useState<any[]>(() => loadState('carsan_opportunities', []));
    const [auditLogs, setAuditLogs] = useState<AuditLog[]>(() => loadState('carsan_audit_logs', []));

    useEffect(() => localStorage.setItem('carsan_projects', JSON.stringify(projects)), [projects]);
    useEffect(() => localStorage.setItem('carsan_materials', JSON.stringify(materials)), [materials]);
    useEffect(() => localStorage.setItem('carsan_tickets', JSON.stringify(tickets)), [tickets]);
    useEffect(() => localStorage.setItem('carsan_purchases', JSON.stringify(purchases)), [purchases]);
    useEffect(() => localStorage.setItem('carsan_leads', JSON.stringify(leads)), [leads]);
    useEffect(() => localStorage.setItem('carsan_opportunities', JSON.stringify(opportunities)), [opportunities]);
    useEffect(() => localStorage.setItem('carsan_audit_logs', JSON.stringify(auditLogs)), [auditLogs]);

    const logActivity = (action: string, details: string) => {
        if (!user) return;
        const log: AuditLog = { id: Date.now().toString(), userId: user.id, userName: user.name, action, details, timestamp: new Date().toISOString() };
        setAuditLogs(prev => [log, ...prev].slice(0, 100));
    };

    const handleLogin = (u: User) => { setUser(u); localStorage.setItem('carsan_user', JSON.stringify(u)); logActivity('Login', 'User logged in'); };
    const handleLogout = () => { 
        import('./services/emailIntegration').then(m => m.signOut()); 
        setUser(null); localStorage.removeItem('carsan_user'); setCurrentView(ViewState.DASHBOARD); window.location.reload(); 
    };

    if (!user) return <Login onLogin={handleLogin} />;

    const renderView = () => {
        switch (currentView) {
            case ViewState.DASHBOARD: return (
                <div className="p-4 md:p-8 max-w-7xl mx-auto">
                    <h1 className="text-3xl font-bold mb-6 text-slate-900">Command Center</h1>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200"><h3 className="text-slate-500 font-bold uppercase text-xs mb-2">Revenue Won (YTD)</h3><p className="text-2xl font-bold text-emerald-600">${projects.filter(p => p.status === 'Won').reduce((sum, p) => sum + (p.contractValue || 0), 0).toLocaleString()}</p></div>
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200"><h3 className="text-slate-500 font-bold uppercase text-xs mb-2">Pipeline Value</h3><p className="text-2xl font-bold text-blue-600">${projects.filter(p => p.status === 'Draft' || p.status === 'Sent').reduce((sum, p) => sum + (p.contractValue || 0), 0).toLocaleString()}</p></div>
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200"><h3 className="text-slate-500 font-bold uppercase text-xs mb-2">Service Revenue</h3><p className="text-2xl font-bold text-indigo-600">${tickets.filter(t => t.status === 'Authorized' || t.status === 'Completed').reduce((sum, t) => { const mat = t.items.reduce((s, i) => s + (i.quantity * i.unitMaterialCost), 0); const lab = t.items.reduce((s, i) => s + (i.quantity * i.unitLaborHours * t.laborRate), 0); return sum + mat + lab; }, 0).toLocaleString()}</p></div>
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200"><h3 className="text-slate-500 font-bold uppercase text-xs mb-2">Purchase Spend</h3><p className="text-2xl font-bold text-slate-700">${purchases.reduce((sum, p) => sum + (p.totalCost || 0), 0).toLocaleString()}</p></div>
                    </div>
                    {/* Quick Actions & Action Items */}
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                        <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="font-bold text-slate-800 mb-4">Action Items</h3>
                            {/* ... Action Items List ... */}
                        </div>
                        <div className="bg-slate-900 text-white p-6 rounded-xl shadow-lg">
