                                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                                    <h3 className="font-bold text-slate-800 mb-4">Operations</h3>
                                    <div className="space-y-4">
                                        <div className="flex justify-between items-center">
                                            <span className="text-sm text-slate-600">Active Projects (Ongoing)</span>
                                            <span className="font-bold text-slate-900 bg-emerald-100 text-emerald-800 px-2 py-0.5 rounded text-xs">
                                                {projects.filter(p => p.status === 'Ongoing').length}
                                            </span>
                                        </div>
                                        <div className="flex justify-between items-center">
                                            <span className="text-sm text-slate-600">Pending Change Orders</span>
                                            <span className="font-bold text-slate-900 bg-blue-100 text-blue-800 px-2 py-0.5 rounded text-xs">
                                                {tickets.filter(t => t.status === 'Sent').length}
                                            </span>
                                        </div>
                                        <div className="flex justify-between items-center">
                                            <span className="text-sm text-slate-600">Open Leads</span>
                                            <span className="font-bold text-slate-900 bg-slate-100 text-slate-800 px-2 py-0.5 rounded text-xs">
                                                {leads.length}
                                            </span>
                                        </div>
                                    </div>
                                </div>

                                <div className="bg-slate-900 text-white p-6 rounded-xl shadow-lg">
                                    <h3 className="font-bold text-lg mb-2">Quick Actions</h3>
                                    <div className="space-y-2">
                                        <button onClick={() => setCurrentView(ViewState.ESTIMATE_NEW)} className="w-full text-left px-3 py-2 hover:bg-white/10 rounded-lg text-sm transition">
                                            + New Estimate
                                        </button>
                                        <button onClick={() => setCurrentView(ViewState.SERVICE)} className="w-full text-left px-3 py-2 hover:bg-white/10 rounded-lg text-sm transition">
                                            + New Change Order
                                        </button>
                                        <button onClick={() => setCurrentView(ViewState.CRM)} className="w-full text-left px-3 py-2 hover:bg-white/10 rounded-lg text-sm transition">
                                            + Add CRM Lead
                                        </button>
                                    </div>
                                </div>

                                {/* 4. Activity Log (Admin Only) */}
                                {user.role === 'admin' && (
                                    <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200">
                                        <h3 className="font-bold text-slate-800 mb-2 text-sm">Recent Activity</h3>
                                        <div className="space-y-2 max-h-40 overflow-y-auto text-xs text-slate-500 custom-scrollbar">
                                            {auditLogs.length === 0 ? (
                                                <p className="italic">No activity recorded.</p>
                                            ) : (
                                                auditLogs.slice(0, 5).map(log => (
                                                    <div key={log.id} className="border-b border-slate-50 pb-1 mb-1 last:border-0">
                                                        <span className="font-bold text-slate-700">{log.userName}</span>: {log.details}
                                                        <br/><span className="text-[10px] text-slate-300">{new Date(log.timestamp).toLocaleTimeString()}</span>
                                                    </div>
                                                ))
                                            )}
                                        </div>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                );
            case ViewState.PROJECTS: return <ProjectList projects={projects} setProjects={setProjects} onOpenProject={() => {}} tickets={tickets} />;
            case ViewState.ESTIMATE_NEW: return <Estimator materials={materials} projects={projects} />;
            case ViewState.DATABASE: return <PriceDatabase materials={materials} setMaterials={setMaterials} />;
            case ViewState.CRM: return <CRM leads={leads} setLeads={setLeads} opportunities={opportunities} setOpportunities={setOpportunities} projects={projects} setProjects={setProjects} />;
            case ViewState.SERVICE: return <ServiceModule user={user} materials={materials} projects={projects} tickets={tickets} setTickets={setTickets} />;
            case ViewState.PRICE_ANALYSIS: return <PriceAnalysis purchases={purchases} setPurchases={setPurchases} materials={materials} setMaterials={setMaterials} projects={projects} />;
            case ViewState.CLOUD_DB: return <SharePointConnect projects={projects} setProjects={setProjects} materials={materials} tickets={tickets} purchases={purchases} setPurchases={setPurchases} />;
            default: return <div>View Not Found</div>;
        }
    };

    return (
        <div className="flex h-screen bg-slate-100 overflow-hidden font-sans text-slate-900">
            <Sidebar currentView={currentView} onChangeView={setCurrentView} isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} user={user} onLogout={handleLogout} />
            <main className="flex-1 flex flex-col relative overflow-hidden md:ml-64 transition-all duration-300">
                <div className="md:hidden bg-slate-900 text-white p-4 flex justify-between items-center shrink-0"><span className="font-bold">CARSAN Electric</span><button onClick={() => setIsSidebarOpen(true)}>Menu</button></div>
                <div className="flex-1 overflow-auto">{renderView()}</div>
                <AIAssistant projects={projects} materials={materials} tickets={tickets} />
            </main>
        </div>
    );
};

import React, { useState } from 'react';
import { Lead, ProjectEstimate } from '../types';
import { fetchOutlookEmails, getStoredTenantId, setStoredTenantId, getStoredClientId, setStoredClientId } from '../services/emailIntegration';
import { Mail, RefreshCw, Settings, User as UserIcon, Phone, Search, Save, Loader2, Trello, List, ArrowRight, CheckCircle, XCircle, DollarSign, Plus, ArrowUpRight, ArrowDownRight, Trophy, AlertCircle, Trash2 } from 'lucide-react';

interface CRMProps {
    leads: Lead[];
    setLeads: (leads: Lead[]) => void;
    opportunities: any[];
    setOpportunities: (opps: any[]) => void;
    projects?: ProjectEstimate[];
    setProjects?: (projects: ProjectEstimate[]) => void;
}

export const CRM: React.FC<CRMProps> = ({ leads, setLeads, opportunities, setOpportunities, projects = [], setProjects }) => {
    const [activeTab, setActiveTab] = useState<'pipeline' | 'leads'>('pipeline');
    const [isLoading, setIsLoading] = useState(false);
    const [showSettings, setShowSettings] = useState(false);

    // Settings State
    const [tenantId, setTenantId] = useState(getStoredTenantId() || '');
    const [clientId, setClientId] = useState(getStoredClientId() || '');

    // Financial KPIs
    const currentYear = new Date().getFullYear();
    const lastYear = currentYear - 1;

    const getProjectValue = (year: number, status: string) => {
        if (!projects) return 0;
        return projects
            .filter(p => new Date(p.dateCreated).getFullYear() === year)
            .filter(p => status === 'All' || p.status === status)
            .reduce((sum, p) => sum + (p.contractValue || 0), 0);
    };

    const sentThisYear = getProjectValue(currentYear, 'Sent');
    const wonThisYear = getProjectValue(currentYear, 'Won');
    const lostThisYear = getProjectValue(currentYear, 'Lost');
    const sentLastYear = getProjectValue(lastYear, 'Sent');
    const wonLastYear = getProjectValue(lastYear, 'Won');

    const calcGrowth = (current: number, past: number) => {
        if (past === 0) return 100;
        return ((current - past) / past) * 100;
    };

    const handleFetchLeads = async () => {
        setIsLoading(true);
        try {
            const data = await fetchOutlookEmails();
            const newLeads = [...leads];
            data.forEach(d => {
                if (!newLeads.find(l => l.id === d.id)) {
                    newLeads.unshift(d);
                }
            });
            setLeads(newLeads);
        } catch (error) {
            console.error(error);
            alert("Failed to fetch leads. Check your Azure configuration.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleSaveSettings = () => {
        setStoredTenantId(tenantId.trim());
        setStoredClientId(clientId.trim());
        setShowSettings(false);
        alert("Settings saved!");
    };

    const convertToOpportunity = (lead: Lead) => {
        if (!setProjects) return;
        const newProject: ProjectEstimate = {
            id: `proj-${Date.now()}`,
            name: lead.name,
            client: lead.name,
            contactInfo: lead.email,
            address: 'Miami, FL',
            status: 'Draft',
            dateCreated: new Date().toISOString(),
            laborRate: 75,
            items: [],
            contractValue: 0
        };
        setProjects([...projects, newProject]);
        setLeads(leads.filter(l => l.id !== lead.id));
        setActiveTab('pipeline');
    };

    // Updated moveStage to handle Project Statuses: Draft -> Sent -> Won
    const moveStage = (projectId: string, direction: 'next' | 'prev') => {
        if (!setProjects) return;
        const stages = ['Draft', 'Sent', 'Won', 'Lost'];
        const updated = projects.map(p => {
            if (p.id === projectId) {
                const idx = stages.indexOf(p.status);
                let newIdx = idx;
                if (direction === 'next' && idx < stages.length - 1) newIdx++;
                if (direction === 'prev' && idx > 0) newIdx--;
                // Prevent accidental move from Won to Lost via arrow if index logic causes it.
                // Draft(0) -> Sent(1) -> Won(2) -> Lost(3).
                // Actually this flow is fine, user can choose.
                return { ...p, status: stages[newIdx] as any };
            }
            return p;
        });
        setProjects(updated);
    };

    const markAsLost = (projectId: string) => {
        if (!setProjects) return;
        if(confirm("Mark this project as Lost?")) {
            setProjects(projects.map(p => p.id === projectId ? { ...p, status: 'Lost' } : p));
        }
    };

    const deleteProject = (id: string) => {
        if (!setProjects) return;
        if(confirm("Delete this project permanently?")) {
            setProjects(projects.filter(p => p.id !== id));
        }
    };

    const discardLead = (id: string) => {
        if(confirm("Discard this lead?")) {
            setLeads(leads.filter(l => l.id !== id));
        }
    };

    const handleForwardLead = (lead: Lead) => {
        const subject = `Lead Forward: ${lead.name}`;
        const body = `Hi Simon,\n\nPlease review this lead.\n\nName: ${lead.name}\nEmail: ${lead.email}\nNotes: ${lead.notes}\n\nThanks.`;
        window.open(`mailto:simon.martinez@carsanelectric.com?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`);
    };

    return (
        <div className="p-4 md:p-8 max-w-7xl mx-auto space-y-6 h-full flex flex-col">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 shrink-0">
                <div>
                    <h1 className="text-3xl font-bold text-slate-900 tracking-tight">CRM & Pipeline</h1>
                    <p className="text-slate-500 mt-1">Track relationships, leads, and deal flow.</p>
                </div>
                <div className="flex gap-2">
                    <button 
                        onClick={() => setShowSettings(!showSettings)}
                        className={`p-2 rounded-lg border transition-colors ${showSettings ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-200 text-slate-500'}`}
                        title="Configuration"
                    >
                        <Settings className="w-5 h-5" />
                    </button>
                    <div className="bg-slate-100 p-1 rounded-lg flex">
                        <button 
                            onClick={() => setActiveTab('pipeline')}
                            className={`px-4 py-2 rounded-md text-sm font-medium transition-all flex items-center gap-2 ${activeTab === 'pipeline' ? 'bg-white shadow text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
                        >
                            <Trello className="w-4 h-4" /> Pipeline
                        </button>
                        <button 
                            onClick={() => setActiveTab('leads')}
                            className={`px-4 py-2 rounded-md text-sm font-medium transition-all flex items-center gap-2 ${activeTab === 'leads' ? 'bg-white shadow text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
                        >
                            <List className="w-4 h-4" /> Leads
                        </button>
                    </div>
                </div>
            </div>

            {showSettings && (
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 animate-in slide-in-from-top-2">
                    <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
                        <Settings className="w-4 h-4" /> Azure Integration Settings
                    </h3>
                    <div className="bg-blue-50 p-4 rounded-lg mb-6 text-sm text-blue-800">
                        <p className="font-bold mb-1">Vercel Deployment</p>
                        <p>Redirect URI: <code className="bg-white px-1 py-0.5 rounded border">{window.location.origin}</code></p>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="text-xs font-bold text-slate-500 uppercase block mb-1">Azure Tenant ID</label>
                            <input 
                                value={tenantId}
                                onChange={(e) => setTenantId(e.target.value)}
                                placeholder="e.g. 555y1dg..."
                                className="w-full text-sm border border-slate-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 outline-none"
                            />
                            <p className="text-[10px] text-slate-400 mt-1">Found in Overview &gt; Directory (tenant) ID.</p>
                        </div>
                        <div>
                            <label className="text-xs font-bold text-slate-500 uppercase block mb-1">Client ID</label>
                            <input 
                                value={clientId}
                                onChange={(e) => setClientId(e.target.value)}
                                placeholder="Application (client) ID"
                                className="w-full text-sm border border-slate-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 outline-none"
                            />
                        </div>
                    </div>
                    <div className="mt-4 flex justify-end">
                        <button onClick={handleSaveSettings} className="bg-slate-900 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2">
                            <Save className="w-4 h-4" /> Save Configuration
                        </button>
                    </div>
                </div>
            )}

            {/* FINANCIAL KPIS */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm relative overflow-hidden">
                    <div className="absolute right-0 top-0 p-4 opacity-10"><DollarSign className="w-16 h-16 text-blue-500" /></div>
                    <p className="text-xs font-bold text-slate-400 uppercase">Total Quoted (YTD)</p>
                    <p className="text-2xl font-bold text-slate-900 mt-1">${sentThisYear.toLocaleString()}</p>
                    <div className={`flex items-center gap-1 text-xs font-bold mt-2 ${calcGrowth(sentThisYear, sentLastYear) >= 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                        {calcGrowth(sentThisYear, sentLastYear) >= 0 ? <ArrowUpRight className="w-3 h-3" /> : <ArrowDownRight className="w-3 h-3" />}
                        {Math.abs(calcGrowth(sentThisYear, sentLastYear)).toFixed(1)}% vs Last Year
                    </div>
                </div>
                <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm relative overflow-hidden">
                    <div className="absolute right-0 top-0 p-4 opacity-10"><Trophy className="w-16 h-16 text-emerald-500" /></div>
                    <p className="text-xs font-bold text-slate-400 uppercase">Total Won (YTD)</p>
                    <p className="text-2xl font-bold text-emerald-600 mt-1">${wonThisYear.toLocaleString()}</p>
                    <div className={`flex items-center gap-1 text-xs font-bold mt-2 ${calcGrowth(wonThisYear, wonLastYear) >= 0 ? 'text-emerald-600' : 'text-red-500'}`}>
                        {calcGrowth(wonThisYear, wonLastYear) >= 0 ? <ArrowUpRight className="w-3 h-3" /> : <ArrowDownRight className="w-3 h-3" />}
                        {Math.abs(calcGrowth(wonThisYear, wonLastYear)).toFixed(1)}% vs Last Year
                    </div>
                </div>
                <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm relative overflow-hidden">
                    <div className="absolute right-0 top-0 p-4 opacity-10"><XCircle className="w-16 h-16 text-red-500" /></div>
                    <p className="text-xs font-bold text-slate-400 uppercase">Lost Revenue (YTD)</p>
                    <p className="text-2xl font-bold text-red-500 mt-1">${lostThisYear.toLocaleString()}</p>
                    <p className="text-xs text-slate-400 mt-2">Opportunities for review</p>
                </div>
            </div>

            {/* --- PIPELINE VIEW --- */}
            {activeTab === 'pipeline' && (
                <div className="flex-1 overflow-x-auto min-h-[500px] pb-4">
                    <div className="flex gap-4 min-w-[1000px] h-full">
                        {['Draft', 'Sent', 'Won', 'Lost'].map(stage => {
                            // Filter by project status and sort by Date Created (Newest First)
                            const stageOpps = projects
                                .filter(p => p.status === stage)
                                .sort((a, b) => new Date(b.dateCreated).getTime() - new Date(a.dateCreated).getTime());

                            const totalValue = stageOpps.reduce((sum, p) => sum + (p.contractValue || 0), 0);

                            return (
                                <div key={stage} className="flex-1 bg-slate-100 rounded-xl p-3 flex flex-col h-full border border-slate-200">
                                    <div className="flex justify-between items-center mb-3 px-1">
                                        <h3 className={`font-bold text-sm uppercase ${stage === 'Won' ? 'text-emerald-700' : stage === 'Lost' ? 'text-red-700' : 'text-slate-700'}`}>{stage}</h3>
                                        <span className="text-xs font-medium text-slate-500 bg-white px-2 py-0.5 rounded-full border">{stageOpps.length}</span>
                                    </div>
                                    <div className="mb-3 text-right px-1">
                                        <span className="text-xs text-slate-400 font-medium">${totalValue.toLocaleString()}</span>
                                    </div>

                                    <div className="flex-1 space-y-3 overflow-y-auto custom-scrollbar">
                                        {stageOpps.map(project => (
                                            <div key={project.id} className="bg-white p-3 rounded-lg shadow-sm border border-slate-200 group hover:shadow-md transition-all">
                                                <div className="flex justify-between items-start mb-2">
                                                    <span className="text-xs font-bold text-blue-600 bg-blue-50 px-1.5 py-0.5 rounded truncate max-w-[100px]">{project.client}</span>
                                                    <button onClick={() => deleteProject(project.id)} className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition"><Trash2 className="w-4 h-4" /></button>
                                                </div>
                                                <h4 className="font-bold text-slate-800 text-sm mb-1">{project.name}</h4>
                                                <p className="text-xs text-slate-500 truncate">{project.contactInfo || project.address}</p>
                                                <p className="text-[10px] text-slate-400 mt-1">{new Date(project.dateCreated).toLocaleDateString()}</p>
                                                <div className="mt-3 pt-3 border-t border-slate-100 flex justify-between items-center">
                                                    <span className="font-bold text-slate-700 text-sm">${(project.contractValue || 0).toLocaleString()}</span>
                                                    <div className="flex gap-1">
                                                        {stage !== 'Draft' && (
                                                            <button onClick={() => moveStage(project.id, 'prev')} className="p-1 hover:bg-slate-100 rounded text-slate-400 hover:text-slate-600" title="Move Back">
                                                                <ArrowRight className="w-4 h-4 rotate-180" />
                                                            </button>
                                                        )}
                                                        {stage !== 'Lost' && (
                                                            <button onClick={() => moveStage(project.id, 'next')} className="p-1 hover:bg-blue-50 rounded text-blue-400 hover:text-blue-600" title={stage === 'Won' ? "Move to Lost" : "Move Forward"}>
                                                                <ArrowRight className="w-4 h-4" />
                                                            </button>
                                                        )}
                                                        {stage !== 'Lost' && stage !== 'Won' && (
                                                            <button onClick={() => markAsLost(project.id)} className="p-1 hover:bg-red-50 rounded text-slate-300 hover:text-red-500" title="Mark Lost">
                                                                <XCircle className="w-4 h-4" />
                                                            </button>
                                                        )}
                                                    </div>
                                                </div>
                                            </div>
                                        ))}
                                        {stage === 'Draft' && (
                                            <button 
                                                onClick={() => {
                                                    const name = prompt("Enter Project Name:");
                                                    if(name && setProjects) {
                                                        const newProject: ProjectEstimate = {
                                                            id: `proj-${Date.now()}`,
                                                            name: name,
                                                            client: 'New Client',
                                                            contactInfo: '',
                                                            address: 'Miami, FL',
                                                            status: 'Draft',
                                                            dateCreated: new Date().toISOString(),
                                                            laborRate: 75,
                                                            items: [],
                                                            contractValue: 0
                                                        };
                                                        setProjects([...projects, newProject]);
                                                    }
                                                }}
                                                className="w-full py-2 border-2 border-dashed border-slate-300 rounded-lg text-slate-400 text-sm font-bold hover:border-blue-400 hover:text-blue-500 hover:bg-white transition flex items-center justify-center gap-2"
                                            >
                                                <Plus className="w-4 h-4" /> Add Project
                                            </button>
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}

            {/* --- LEADS VIEW --- */}
            {activeTab === 'leads' && (
                <div className="flex-1 flex flex-col bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                    <div className="p-4 border-b border-slate-200 flex justify-between items-center bg-slate-50">
                        <div className="flex items-center gap-2">
                            <h3 className="font-bold text-slate-800">Recent Leads</h3>
                            <span className="bg-blue-100 text-blue-700 text-xs px-2 py-0.5 rounded-full font-bold">{leads.length}</span>
                        </div>
                        <button 
                            onClick={handleFetchLeads}
                            disabled={isLoading}
                            className="text-blue-600 text-sm font-bold hover:bg-blue-50 px-3 py-1.5 rounded-lg transition flex items-center gap-2 disabled:opacity-50"
                        >
                            {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <RefreshCw className="w-4 h-4" />}
                            Sync Outlook
                        </button>
                    </div>
                    <div className="flex-1 overflow-auto">
                        <table className="w-full text-left text-sm">
                            <thead className="bg-white border-b border-slate-200 text-slate-500 font-bold uppercase text-xs sticky top-0">
                                <tr>
                                    <th className="px-6 py-4">Source</th>
                                    <th className="px-6 py-4">Name</th>
                                    <th className="px-6 py-4">Email</th>
                                    <th className="px-6 py-4">Notes</th>
                                    <th className="px-6 py-4 text-center">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {leads.map(lead => (
                                    <tr key={lead.id} className="hover:bg-slate-50 group">
                                        <td className="px-6 py-4">
                                            <span className="flex items-center gap-2 text-slate-600 font-medium">
                                                <Mail className="w-4 h-4 text-blue-500" /> Outlook
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 font-bold text-slate-900">{lead.name}</td>
                                        <td className="px-6 py-4 text-slate-600">{lead.email}</td>
                                        <td className="px-6 py-4 text-slate-500 text-xs max-w-xs truncate" title={lead.notes}>{lead.notes}</td>
                                        <td className="px-6 py-4 flex justify-center gap-2">
                                            <button 
                                                onClick={() => handleForwardLead(lead)} 
                                                className="p-1.5 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded" 
                                                title="Forward to Simon"
                                            >
                                                <ArrowRight className="w-4 h-4" />
                                            </button>
                                            <button 
                                                onClick={() => convertToOpportunity(lead)} 
                                                className="p-1.5 text-slate-400 hover:text-emerald-600 hover:bg-emerald-50 rounded" 
                                                title="Convert to Project (Draft)"
                                            >
                                                <CheckCircle className="w-4 h-4" />
                                            </button>
                                            <button 
                                                onClick={() => discardLead(lead.id)} 
                                                className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded" 
                                                title="Discard"
                                            >
                                                <XCircle className="w-4 h-4" />
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { Search, Upload, Loader2, Database, AlertTriangle, RefreshCw, LogOut, FileSpreadsheet, DollarSign } from 'lucide-react';
import { searchSharePointSites, getSharePointLists, addListItem, SPSite, ensureCarsanLists, getAllProjects, getAllPurchaseRecords } from '../services/sharepointService';
import { normalizeSupplier, parseCurrency } from '../utils/purchaseData';
import { signOut } from '../services/emailIntegration';

interface SharePointConnectProps {
    projects: any[];
    setProjects?: (projects: any[]) => void;
    materials: any[];
    tickets: any[];
    purchases?: any[];
    setPurchases?: (purchases: any[]) => void;
}

interface RowError {
    row: number;
    message: string;
}

export const SharePointConnect: React.FC<SharePointConnectProps> = ({ projects, setProjects, materials, tickets, purchases, setPurchases }) => {
    const [step, setStep] = useState<number>(0);
    const [sites, setSites] = useState<SPSite[]>([]);
    const [selectedSite, setSelectedSite] = useState<SPSite | null>(null);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [statusMsg, setStatusMsg] = useState<string>("");
    const [rowErrors, setRowErrors] = useState<RowError[]>([]);

    const handleSearchSites = async () => {
        setIsLoading(true); setError(null);
        try { const results = await searchSharePointSites(""); setSites(results); } 
        catch (e: any) { setError(e.message || "Failed to fetch sites"); } 
        finally { setIsLoading(false); }
    };

    const handleSelectSite = (site: SPSite) => { setSelectedSite(site); setStep(1); };

    const handleInitialize = async (forceNewToken = false) => {
        if (!selectedSite) return;
        setIsLoading(true); setStatusMsg("Initializing Database Lists (Checking Schema)..."); setError(null);
        try {
            await ensureCarsanLists(selectedSite.id, forceNewToken);
            setStatusMsg("Database Ready! Lists verified and columns updated.");
        } catch (e: any) {
            console.error("Init Error", e);
            setStatusMsg("Error creating lists.");
            setError(e.message || "Access Denied.");
        } finally { setIsLoading(false); }
    };

    const handleLogout = async () => { await signOut(); window.location.reload(); };

    const handleSyncDown = async () => {
        if (!selectedSite || !setProjects) return;
        setIsLoading(true); setStatusMsg("Downloading projects...");
        try {
            const cloudProjects = await getAllProjects(selectedSite.id);
            if (cloudProjects.length > 0) {
                setProjects(cloudProjects);
                setStatusMsg(`Success! Downloaded ${cloudProjects.length} projects.`);
                alert(`Sync Complete! Loaded ${cloudProjects.length} projects.`);
            } else { setStatusMsg("No projects found in cloud."); }
        } catch (e: any) { console.error(e); setError("Failed: " + e.message); } 
        finally { setIsLoading(false); }
    };

    const handlePurchaseSyncDown = async () => {
        if (!selectedSite || !setPurchases) return;
        setIsLoading(true); setStatusMsg("Downloading purchase history...");
        try {
            const cloudPurchases = await getAllPurchaseRecords(selectedSite.id);
            if (cloudPurchases.length > 0) {
                setPurchases(cloudPurchases);
                setStatusMsg(`Success! Downloaded ${cloudPurchases.length} records.`);
                alert(`Sync Complete! Loaded ${cloudPurchases.length} purchase records.`);
            } else { setStatusMsg("No purchase records found in cloud."); }
        } catch (e: any) { console.error(e); setError("Failed: " + e.message); } 
        finally { setIsLoading(false); }
    };

    // --- CRITICAL FIX: DD/MM/YYYY Date Parsing ---
    const parseExcelDate = (val: any) => {
        if (!val) return null;

        // 1. Handle Excel Serial Numbers (e.g. 45321)
        if (typeof val === 'number') {
            return new Date(Math.round((val - 25569) * 86400 * 1000)).toISOString();
        }

        // 2. Handle Strings
        if (typeof val === 'string') {
            let cleanVal = val.trim();

            // Check for DD/MM/YYYY (e.g. 25/12/2024 or 1/2/2025)
            const dmyMatch = cleanVal.match(/^(\d{1,2})[\/.-](\d{1,2})[\/.-](\d{4})/);
            if (dmyMatch) {
                // dmyMatch[1] = Day, [2] = Month, [3] = Year
                // Construct proper ISO string YYYY-MM-DD
                const d = new Date(`${dmyMatch[3]}-${dmyMatch[2]}-${dmyMatch[1]}`);
                if (!isNaN(d.getTime())) return d.toISOString();
            }

            // Fallback: Try standard Date parsing (for ISO strings or MM/DD/YYYY)
            const d = new Date(cleanVal);
            if (!isNaN(d.getTime()) && d.getFullYear() > 1970) return d.toISOString();
        }
        return null; // Return null if invalid, so SharePoint ignores it rather than crashing
    };

    // Helper to find keys with loose matching (ignores case, extra spaces, underscores)
    const findValWithFuzzyMatch = (row: any, keys: string[]) => {
        const rowKeys = Object.keys(row);
        const normalize = (s: string) => s.toLowerCase().replace(/[\s_-]+/g, '').trim();

        for (const key of keys) {
            // 1. Exact match (fastest)
            if (row[key] !== undefined) return row[key];

            // 2. Fuzzy match
            const searchKey = normalize(key);
            const foundKey = rowKeys.find(k => normalize(k) === searchKey);
            if (foundKey && row[foundKey] !== undefined) return row[foundKey];
        }
        return undefined;
    };

    const handlePurchaseHistoryUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]; if (!file || !selectedSite) return;
        setIsLoading(true); setRowErrors([]); setStatusMsg("Reading Excel...");
        try {
            const lists = await getSharePointLists(selectedSite.id);
            const purchaseList = lists.find(l => l.displayName === 'Carsan_Purchases');
            if (!purchaseList) throw new Error("List 'Carsan_Purchases' not found.");

            const reader = new FileReader();
            reader.onload = async (event) => {
                const data = event.target?.result;
                const workbook = XLSX.read(data, { type: 'array' });
                const jsonData = XLSX.utils.sheet_to_json(workbook.Sheets[workbook.SheetNames[0]]);
                setStatusMsg(`Uploading ${jsonData.length} records...`);
                let successCount = 0; let failCount = 0;

                for (let i = 0; i < jsonData.length; i++) {
                    const row: any = jsonData[i];
                    try {
                        const findVal = (keys: string[]) => findValWithFuzzyMatch(row, keys);

                        await addListItem(selectedSite.id, purchaseList.id, {
                            Title: `PO-${findVal(['PO Number', 'PO']) || i}`,
                            PurchaseDate: parseExcelDate(findVal(['Date', 'Invoice Date'])),
                            PO_Number: String(findVal(['PO Number', 'PO']) || ''),
                            Brand: String(findVal(['Brand']) || ''),
                            Item_Description: String(findVal(['Item', 'Item Description']) || ''),
                            Quantity: Number(findVal(['Quantity', 'Qty']) || 0),
                            Unit_Cost: parseCurrency(String(findVal(['Unit Cost', 'Price']) || 0)),
                            Tax: parseCurrency(String(findVal(['TAX', 'Tax']) || 0)),
                            Total_Cost: parseCurrency(String(findVal(['Total', 'Total Cost']) || 0)),
                            Supplier: normalizeSupplier(String(findVal(['Supplier']) || '')),
                            Project_Name: String(findVal(['Project']) || ''),
                            Item_Type: String(findVal(['TYPE']) || ''),
                            JSON_Data: JSON.stringify(row)
                        });
                        successCount++;
                    } catch (err: any) { failCount++; setRowErrors(prev => [...prev, { row: i + 2, message: err.message }]); }
                    if (i % 5 === 0) { setStatusMsg(`Uploading... ${i + 1} / ${jsonData.length}`); await new Promise(resolve => setTimeout(resolve, 50)); }
                }
                setStatusMsg(`Finished. Success: ${successCount}, Fail: ${failCount}`); setIsLoading(false); alert(`Uploaded ${successCount} records.`);
            };
            reader.readAsArrayBuffer(file);
        } catch (e: any) { setError(e.message); setIsLoading(false); }
    };

    const handleExcelToCloud = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]; if (!file || !selectedSite) return;
        setIsLoading(true); setRowErrors([]); setStatusMsg("Reading Project Excel...");
        const reader = new FileReader();
        reader.onload = async (event) => {
            try {
                const data = event.target?.result;
                const workbook = XLSX.read(data, { type: 'array' });
                const jsonData = XLSX.utils.sheet_to_json(workbook.Sheets[workbook.SheetNames[0]]);
                const lists = await getSharePointLists(selectedSite.id);
                const projectList = lists.find((l: any) => l.displayName === 'Carsan_Projects');
                if (!projectList) throw new Error("List 'Carsan_Projects' not found.");

                let successCount = 0; let failCount = 0;
                setStatusMsg(`Uploading ${jsonData.length} projects...`);

                for (let i = 0; i < jsonData.length; i++) {
                    const row: any = jsonData[i];
                    const findVal = (keys: string[]) => findValWithFuzzyMatch(row, keys);

                    try {
                        // Use the strict date parser
                        const deliveryDate = parseExcelDate(findVal(['Delivery Date', 'Due Date']));
                        const expirationDate = parseExcelDate(findVal(['Expiration Date', 'Valid Until']));
                        const awardedDate = parseExcelDate(findVal(['Awarded Date', 'Start Date']));

                        await addListItem(selectedSite.id, projectList.id, {
                            Title: findVal(['Project Name', 'Title', 'Project']) || 'Untitled',
                            Client: findVal(['Client', 'Customer']) || 'Unknown',
                            Status: findVal(['Status']) || 'Draft',
                            Value: parseCurrency(String(findVal(['Value', 'Total']) || 0)),
                            ADDRESS: findVal(['ADDRESS', 'Address', 'Location']) || '',
                            Estimator: findVal(['Estimator', 'Owner']) || '',
                            'Delivery Date': deliveryDate, // Now handles DD/MM/YYYY or returns null
                            'Expiration Date': expirationDate,
                            'Awarded Date': awardedDate,
                            JSON_Data: JSON.stringify(row)
                        });
                        successCount++;
                    } catch (err: any) { 
                         failCount++; 
                         setRowErrors(prev => [...prev, { row: i + 2, message: err.message }]);
                    }
                    if (i % 5 === 0) { setStatusMsg(`Uploading project ${i + 1} of ${jsonData.length}...`); await new Promise(resolve => setTimeout(resolve, 100)); }
                }
                setStatusMsg(`Finished. Success: ${successCount}, Fail: ${failCount}`); setIsLoading(false); alert(`Uploaded ${successCount} projects.`);
            } catch (err: any) { setError(err.message); setIsLoading(false); if (e.target) e.target.value = ''; }
        };
        reader.readAsArrayBuffer(file);
    };

    return (
        <div className="p-8 max-w-4xl mx-auto">
            <h1 className="text-2xl font-bold mb-6 flex items-center gap-2"><Database className="w-8 h-8 text-blue-600" /> Cloud Database Manager</h1>
            {step === 0 && (
                <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                    <h2 className="text-lg font-bold mb-4">Select SharePoint Site</h2>
                    <div className="bg-blue-50 p-4 rounded-lg mb-6 text-sm text-blue-800 border border-blue-100"><p className="font-bold mb-1">Vercel Redirect URI</p><code className="bg-white px-2 py-1 rounded border text-slate-700 select-all">{window.location.origin}</code></div>
                    <button onClick={handleSearchSites} className="bg-blue-600 text-white px-4 py-2 rounded-lg font-bold text-sm flex items-center gap-2 mb-4 hover:bg-blue-700"><Search className="w-4 h-4" /> Scan for Sites</button>
                    {isLoading && <Loader2 className="w-6 h-6 animate-spin text-blue-500" />}
                    {error && <div className="text-red-500 bg-red-50 p-3 rounded mb-4">{error}</div>}
                    <div className="space-y-2">{sites.map(site => (<div key={site.id} onClick={() => handleSelectSite(site)} className="p-3 border border-slate-200 rounded hover:bg-blue-50 cursor-pointer flex justify-between items-center"><span className="font-medium">{site.displayName}</span><span className="text-xs text-slate-400">{site.webUrl}</span></div>))}</div>
                </div>
            )}
            {step === 1 && selectedSite && (
                <div className="space-y-6">
                    <div className="bg-slate-900 text-white p-4 rounded-xl flex justify-between items-center"><div><p className="text-xs text-slate-400 uppercase">Connected To</p><p className="font-bold">{selectedSite.displayName}</p></div><button onClick={() => setStep(0)} className="text-xs text-blue-400 hover:text-white">Change Site</button></div>

                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200"><h3 className="font-bold text-slate-800 mb-4">1. Provision Lists (Auto-Repair)</h3><p className="text-sm text-slate-500 mb-4">Click this if columns are missing or sync fails.</p>{error && <div className="mb-4 p-3 bg-red-50 border border-red-100 rounded-lg text-sm text-red-600"><strong>Error:</strong> {error} <div className="mt-2 flex gap-2"><button onClick={() => handleInitialize(true)} className="text-xs bg-white border border-red-200 px-2 py-1 rounded font-bold">Retry</button><button onClick={handleLogout} className="text-xs bg-red-600 text-white px-2 py-1 rounded font-bold">Log Out</button></div></div>}<button onClick={() => handleInitialize(true)} disabled={isLoading} className="bg-orange-600 text-white px-6 py-2 rounded-lg font-bold text-sm hover:bg-orange-700 disabled:opacity-50 shadow-sm">{isLoading ? "Processing..." : "Initialize / Repair Database"}</button>{statusMsg && <p className="mt-2 text-sm text-slate-600">{statusMsg}</p>}</div>

                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200"><h3 className="font-bold text-slate-800 mb-4">2. Purchase History (Price Analysis)</h3><p className="text-sm text-slate-500 mb-4">Manage 'Carsan_Purchases' list.</p><div className="grid md:grid-cols-2 gap-4"><div className="border border-slate-200 rounded-lg p-4"><div className="flex items-center gap-2 mb-2 font-bold text-blue-700"><Upload className="w-4 h-4"/> Push (Upload)</div><div className="relative"><input type="file" onChange={handlePurchaseHistoryUpload} accept=".xlsx,.xls,.csv" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" disabled={isLoading} /><button className="w-full bg-blue-50 text-blue-700 border border-blue-200 py-2 rounded-lg text-sm font-bold hover:bg-blue-100">Import Excel</button></div></div><div className="border border-slate-200 rounded-lg p-4"><div className="flex items-center gap-2 mb-2 font-bold text-indigo-700"><RefreshCw className="w-4 h-4"/> Pull (Download)</div><button onClick={handlePurchaseSyncDown} disabled={isLoading || !setPurchases} className="w-full bg-indigo-600 text-white py-2 rounded-lg text-sm font-bold hover:bg-indigo-700 disabled:opacity-50 flex items-center justify-center gap-2">Sync Down from Cloud</button></div></div></div>

                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200"><h3 className="font-bold text-slate-800 mb-4">3. Manage Projects</h3><p className="text-sm text-slate-500 mb-4">Sync project data with <strong>Carsan_Projects</strong>.</p><div className="grid md:grid-cols-2 gap-4"><div className="border border-slate-200 rounded-lg p-4"><div className="flex items-center gap-2 mb-2 font-bold text-emerald-700"><Upload className="w-4 h-4"/> Push (Upload)</div><div className="relative"><input type="file" onChange={handleExcelToCloud} accept=".xlsx,.xls,.csv" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" disabled={isLoading} /><button className="w-full bg-emerald-50 text-emerald-700 border border-emerald-200 py-2 rounded-lg text-sm font-bold hover:bg-emerald-100">Import Excel to Cloud</button></div></div><div className="border border-slate-200 rounded-lg p-4"><div className="flex items-center gap-2 mb-2 font-bold text-blue-700"><RefreshCw className="w-4 h-4"/> Pull (Download)</div><button onClick={handleSyncDown} disabled={isLoading || !setProjects} className="w-full bg-blue-600 text-white py-2 rounded-lg text-sm font-bold hover:bg-blue-700 disabled:opacity-50 flex items-center justify-center gap-2">{isLoading && statusMsg.includes("Downloading") ? <Loader2 className="w-3 h-3 animate-spin"/> : null} Sync Down from Cloud</button></div></div></div>

                    {rowErrors.length > 0 && (
                        <div className="mt-6 p-4 bg-red-50 border border-red-200 rounded-xl animate-in slide-in-from-bottom-4">
                            <div className="flex items-center justify-between mb-3">
                                <h4 className="font-bold text-red-800 flex items-center gap-2"><AlertTriangle className="w-4 h-4" /> Upload Errors ({rowErrors.length})</h4>
                                <button onClick={() => setRowErrors([])} className="text-xs text-red-500 hover:underline font-bold">Clear Log</button>
                            </div>
                            <div className="max-h-60 overflow-y-auto text-xs font-mono text-red-700 bg-white p-3 rounded border border-red-100 shadow-inner custom-scrollbar">
                                {rowErrors.map((e, idx) => (<div key={idx} className="border-b border-red-50 last:border-0 py-1"><span className="font-bold text-slate-500 mr-2">Row {e.row}:</span> {e.message}</div>))}
                            </div>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

import React, { useState, useRef, useEffect } from 'react';
import { ProjectEstimate, ServiceTicket, ProjectFile } from '../types';
import { Search, Upload, Filter, MapPin, ImageIcon, Phone, Download, FileText, ChevronRight, ArrowUpDown, ArrowUp, ArrowDown, Pencil, X, Save, Calendar, DollarSign, User, ExternalLink, List, Map as MapIcon, Plus, Eye, FileSpreadsheet, BellRing, Clock, HardHat, CheckCircle, Briefcase, FolderOpen, FileIcon, Loader2, Sparkles, Wrench, Globe, RefreshCw, Link, Settings, AlertTriangle, Copy, Check, Trash2, FileDiff } from 'lucide-react';
import * as XLSX from 'xlsx';
import { ProjectMap, getPseudoCoordinates } from './ProjectMap';
import { analyzeSchedule } from '../services/geminiService';
import { searchSharePointSites, getSharePointLists, getListColumns, getListItems, SPSite, SPList, SPColumn, SPItem, downloadSharePointImage } from '../services/sharepointService';
import { getStoredTenantId, setStoredTenantId, getStoredClientId, setStoredClientId } from '../services/emailIntegration';

interface ProjectListProps {
  projects: ProjectEstimate[];
  setProjects: (projects: ProjectEstimate[]) => void;
  onOpenProject: (project: ProjectEstimate) => void;
  tickets?: ServiceTicket[];
}

type TabView = 'estimates' | 'ongoing' | 'completed' | 'all';

export const ProjectList: React.FC<ProjectListProps> = ({ projects, setProjects, onOpenProject, tickets = [] }) => {
  const [activeTab, setActiveTab] = useState<TabView>('estimates');
  const [viewMode, setViewMode] = useState<'list' | 'map'>('list');
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('All');
  const [clientFilter, setClientFilter] = useState<string>('All');
  const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'asc' | 'desc' } | null>(null);

  // Modal States
  const [editingProject, setEditingProject] = useState<ProjectEstimate | null>(null);
  const [previewProject, setPreviewProject] = useState<ProjectEstimate | null>(null);

  // SharePoint Sync States
  const [showSharePointModal, setShowSharePointModal] = useState(false);
  const [spStep, setSpStep] = useState<0 | 1 | 2 | 3>(1); 
  const [spSites, setSpSites] = useState<SPSite[]>([]);
  const [spLists, setSpLists] = useState<SPList[]>([]);
  const [spColumns, setSpColumns] = useState<SPColumn[]>([]);
  const [selectedSite, setSelectedSite] = useState<SPSite | null>(null);
  const [selectedList, setSelectedList] = useState<SPList | null>(null);
  const [isLoadingSP, setIsLoadingSP] = useState(false);

  // SP Config Inputs
  const [spTenantId, setSpTenantId] = useState('');
  const [spClientId, setSpClientId] = useState('');
  const [spError, setSpError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  // Mapping Config
  const [fieldMapping, setFieldMapping] = useState<Record<string, string>>({
      name: '',
      client: '',
      status: '',
      value: '',
      image: '',
      address: '',
      dateCreated: ''
  });

  // Schedule Analysis State
  const [isAnalyzingSchedule, setIsAnalyzingSchedule] = useState(false);

  // File Upload Refs
  const fileInputRef = useRef<HTMLInputElement>(null);
  const docInputRef = useRef<HTMLInputElement>(null);
  const scheduleInputRef = useRef<HTMLInputElement>(null);
  const [docCategory, setDocCategory] = useState<ProjectFile['category']>('Other');

  const uniqueEstimators = Array.from(new Set(projects.map(p => p.estimator).filter(Boolean) as string[])).sort();
  const uniqueClients = Array.from(new Set(projects.map(p => p.client).filter(Boolean) as string[])).sort();

  const findValue = (row: any, keys: string[]): any => {
      const rowKeys = Object.keys(row);
      for (const key of keys) {
          if (row[key] !== undefined) return row[key];
          const foundKey = rowKeys.find(k => k.toLowerCase().trim() === key.toLowerCase().trim());
          if (foundKey && row[foundKey] !== undefined) return row[foundKey];
      }
      return undefined;
  };

  const parseDate = (val: any) => {
      if (!val) return undefined;
      // Handle Excel Serial Date
      if (typeof val === 'number') {
          return new Date(Math.round((val - 25569)*86400*1000)).toISOString();
      }
      // Handle String
      const d = new Date(val);
      if (!isNaN(d.getTime())) {
          return d.toISOString();
      }
      return undefined;
  };

  const handleCopyUrl = () => {
      navigator.clipboard.writeText(window.location.origin);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
  };

  // --- SHAREPOINT LOGIC ---

  const handleInitSharePoint = async () => {
      setShowSharePointModal(true);
      setSpError(null);

      const existingTenant = getStoredTenantId();
      const existingClient = getStoredClientId();

      if (!existingTenant) {
          setSpTenantId('');
          setSpClientId(existingClient || '');
          setSpStep(0); 
          return;
      }

      setSpStep(1);
      fetchSPSites();
  };

  const handleSaveSPConfig = () => {
      const trimmedTenant = spTenantId.trim();
      if (!trimmedTenant) {
          alert("Tenant ID is required.");
          return;
      }
      setStoredTenantId(trimmedTenant);
      if (spClientId) setStoredClientId(spClientId.trim());
      setSpError(null);
      setSpStep(1);
      fetchSPSites();
  };

  const fetchSPSites = async () => {
      setIsLoadingSP(true);
      try {
          const sites = await searchSharePointSites("");
          setSpSites(sites);
      } catch (e: any) {
          console.error(e);
          const errStr = String(e).toLowerCase();

          if (errStr.includes("user_cancelled") || errStr.includes("interaction_in_progress")) {
              console.log("Connection cancelled by user.");
              return;
          }

          if (errStr.includes("aadsts50011")) {
              setSpError(`Redirect URI Mismatch.`);
              setSpStep(0);
              return;
          }
          if (errStr.includes("aadsts50194") || errStr.includes("interaction_required")) {
             setSpError("Authentication failed. Check Tenant ID.");
             setSpStep(0);
          } else {
             alert("Could not connect to SharePoint. Ensure you have granted permissions.");
          }
      } finally {
          setIsLoadingSP(false);
      }
  };

  const handleSiteSelect = async (site: SPSite) => {
      setSelectedSite(site);
      setIsLoadingSP(true);
      try {
          const lists = await getSharePointLists(site.id);
          setSpLists(lists);
          setSpStep(2);
      } catch (e) {
          alert("Failed to load lists.");
      } finally {
          setIsLoadingSP(false);
      }
  };

  const handleListSelect = async (list: SPList) => {
      setSelectedList(list);
      setIsLoadingSP(true);
      try {
          const cols = await getListColumns(selectedSite!.id, list.id);
          setSpColumns(cols);

          const guess = { ...fieldMapping };
          cols.forEach((c: SPColumn) => {
              const lower = c.displayName.toLowerCase();
              if (lower.includes('title') || lower.includes('project')) guess.name = c.name;
              if (lower.includes('client') || lower.includes('customer')) guess.client = c.name;
              if (lower.includes('status')) guess.status = c.name;
              if (lower.includes('value') || lower.includes('amount') || lower.includes('price')) guess.value = c.name;
              if (lower.includes('image') || lower.includes('photo') || lower.includes('pic')) guess.image = c.name;
              if (lower.includes('address') || lower.includes('location')) guess.address = c.name;
              if (lower.includes('date') || lower.includes('created')) guess.dateCreated = c.name;
          });
          setFieldMapping(guess);
          setSpStep(3);
      } catch (e) {
          alert("Failed to load columns.");
      } finally {
          setIsLoadingSP(false);
      }
  };

  const handleSharePointSync = async () => {
      if (!selectedSite || !selectedList) return;
      setIsLoadingSP(true);
      try {
          const items = await getListItems(selectedSite.id, selectedList.id);
          const newProjects: ProjectEstimate[] = [];

          for (const item of items) {
              const fields = item.fields;
              let imageUrl = undefined;
              if (fieldMapping.image && fields[fieldMapping.image]) {
                  const rawImg = fields[fieldMapping.image];
                  if (typeof rawImg === 'string' && rawImg.startsWith('http')) {
                      imageUrl = await downloadSharePointImage(rawImg);
                  } else if (typeof rawImg === 'object' && rawImg.serverRelativeUrl) {
                      const fullUrl = `https://${selectedSite.webUrl.split('/')[2]}${rawImg.serverRelativeUrl}`;
                      imageUrl = await downloadSharePointImage(fullUrl);
                  }
              }

              const mappedDate = fieldMapping.dateCreated && fields[fieldMapping.dateCreated] ? parseDate(fields[fieldMapping.dateCreated]) : undefined;
              // Use explicit mapped date -> then Created metadata -> then fallback to Now
              const finalDate = mappedDate || item.createdDateTime || new Date().toISOString();

              newProjects.push({
                  id: `sp-${item.id}`,
                  name: fields[fieldMapping.name] || 'Untitled',
                  client: fields[fieldMapping.client] || 'Unknown',
                  status: fields[fieldMapping.status] || 'Draft',
                  contractValue: Number(fields[fieldMapping.value]) || 0,
                  address: fields[fieldMapping.address] || 'Miami, FL',
                  projectImage: imageUrl,
                  dateCreated: finalDate,
                  laborRate: 75,
                  items: []
              } as ProjectEstimate);
          }

          setProjects([...projects, ...newProjects]);
          alert(`Synced ${newProjects.length} projects from SharePoint!`);
          setShowSharePointModal(false);
      } catch (e) {
          console.error(e);
          alert("Sync failed.");
      } finally {
          setIsLoadingSP(false);
      }
  };

  const handleUpdateProject = (updatedProject: ProjectEstimate) => {
    setProjects(projects.map(p => p.id === updatedProject.id ? updatedProject : p));
    if (editingProject && editingProject.id === updatedProject.id) {
        setEditingProject(null);
    }
  };

  const handleInlineUpdate = (id: string, field: keyof ProjectEstimate, value: any) => {
      const updatedProjects = projects.map(p => {
          if (p.id === id) {
              const updated = { ...p, [field]: value };
              if (field === 'status' && value === 'Ongoing' && !p.startDate) {
                  updated.startDate = new Date().toISOString().split('T')[0];
              }
              if (field === 'status' && value === 'Completed' && !p.completionDate) {
                  updated.completionDate = new Date().toISOString().split('T')[0];
              }
              return updated;
          }
          return p;
      });
      setProjects(updatedProjects);
  };

  const handleStartProject = (project: ProjectEstimate) => {
      if (confirm(`Are you sure you want to start "${project.name}"? This will move it to Ongoing Projects.`)) {
          const updated = { 
              ...project, 
              status: 'Ongoing' as const,
              startDate: new Date().toISOString().split('T')[0] 
          };
          setProjects(projects.map(p => p.id === project.id ? updated : p));
          setActiveTab('ongoing');
          setEditingProject(updated); 
      }
  };

  const handleCompleteProject = (project: ProjectEstimate) => {
      if (confirm(`Mark "${project.name}" as completed?`)) {
          const updated = { 
              ...project, 
              status: 'Completed' as const,
              completionDate: new Date().toISOString().split('T')[0] 
          };
          setProjects(projects.map(p => p.id === project.id ? updated : p));
          setActiveTab('completed');
          setEditingProject(null);
      }
  };

  const handleCreateManualProject = () => {
      const newProject: ProjectEstimate = {
          id: Date.now().toString(),
          name: 'New Project',
          client: 'New Client',
          address: 'Miami, FL',
          dateCreated: new Date().toISOString(),
          status: 'Draft',
          laborRate: 75,
          items: []
      };
      setProjects([newProject, ...projects]);
      setEditingProject(newProject);
  };

  const handleDbUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    e.target.value = '';
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = event.target?.result;
        const workbook = XLSX.read(data, { type: 'array' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        const jsonData = XLSX.utils.sheet_to_json(worksheet);
        if (Array.isArray(jsonData) && jsonData.length > 0) {
            const newProjects: ProjectEstimate[] = jsonData.map((row: any, index: number) => {
                const projectImage = findValue(row, ['Image', 'Photo', 'Image URL', 'Project Image']);
                const phone = findValue(row, ['Phone', 'Client Phone', 'Mobile']);
                const email = findValue(row, ['Email', 'Client Email']);
                const contact = [email, phone].filter(Boolean).join(' | ');

                // Parse Dates
                const deliveryDate = parseDate(findValue(row, ['Delivery Date', 'Due Date']));
                const expirationDate = parseDate(findValue(row, ['Expiration Date', 'Valid Until']));
                const awardedDate = parseDate(findValue(row, ['Awarded Date', 'Start Date']));
                const createdDate = parseDate(findValue(row, ['Date Created', 'Created', 'Date', 'Estimate Date'])) || new Date().toISOString();

                let validImage = undefined;
                if (projectImage && (projectImage.startsWith('http') || projectImage.startsWith('data:'))) {
                    validImage = projectImage;
                }
                return {
                    id: Date.now().toString() + index,
                    name: findValue(row, ['Project Name', 'Project', 'Name', 'Title']) || 'Untitled Project',
                    client: findValue(row, ['Client', 'Customer', 'Client Name']) || 'Unknown Client',
                    address: findValue(row, ['Address', 'Location', 'Site']) || 'Miami, FL',
                    city: findValue(row, ['City', 'Town']) || 'Miami',
                    estimator: findValue(row, ['Estimator', 'Owner', 'Salesperson']) || 'Unassigned',
                    contactInfo: contact || findValue(row, ['Contact', 'Contact Info']),
                    dateCreated: createdDate,
                    deliveryDate: deliveryDate,
                    expirationDate: expirationDate,
                    awardedDate: awardedDate,
                    status: findValue(row, ['Status', 'Stage']) || 'Draft',
                    contractValue: Number(findValue(row, ['Value', 'Amount', 'Price', 'Total', 'Contract Value']) || 0),
                    projectImage: validImage,
                    laborRate: 75,
                    items: []
                };
            });
            setProjects([...projects, ...newProjects]);
            alert(`Imported ${newProjects.length} projects successfully.`);
        } else {
            alert("File processed but no project data found. Please check column headers against the template.");
        }
      } catch (err) {
        console.error(err);
        alert("Failed to parse Excel file. It might be corrupt or encrypted.");
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const handleDownloadTemplate = () => {
      const template = [{
              "Date Created": "2023-05-10",
              "Project Name": "Example Condo Reno",
              "Client": "John Doe Properties",
              "Client Phone": "305-555-0123",
              "Client Email": "john@example.com",
              "Address": "123 Ocean Dr, Miami FL",
              "City": "Miami",
              "Status": "Draft",
              "Value": 15000,
              "Estimator": "Carlos S.",
              "Delivery Date": "2023-05-25",
              "Expiration Date": "2023-06-25",
              "Awarded Date": "",
              "Image URL": "https://example.com/photo.jpg"
      }];
      const worksheet = XLSX.utils.json_to_sheet(template);
      const workbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(workbook, worksheet, "Projects Template");
      XLSX.writeFile(workbook, "Carsan_Projects_Import_Template.xlsx");
  };

  const handleUploadDoc = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file || !editingProject) return;
      const reader = new FileReader();
      reader.onload = (evt) => {
          const base64 = evt.target?.result as string;
          if (docCategory === 'Plan') {
              const updated = { ...editingProject, blueprintImage: base64 };
              handleUpdateProject(updated);
          } else {
              const newDoc: ProjectFile = {
                  id: Date.now().toString(),
                  name: file.name,
                  category: docCategory,
                  uploadDate: new Date().toISOString(),
                  fileData: base64,
                  fileType: file.type
              };
              const updated = { 
                  ...editingProject, 
                  projectFiles: [...(editingProject.projectFiles || []), newDoc] 
              };
              handleUpdateProject(updated);
          }
      };
      reader.readAsDataURL(file);
  };

  const handleAnalyzeSchedule = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file || !editingProject) return;
      setIsAnalyzingSchedule(true);
      const reader = new FileReader();
      reader.onload = async (evt) => {
          const base64 = evt.target?.result as string;
          try {
              const analysis = await analyzeSchedule(base64);
              const updated = { 
                  ...editingProject, 
                  scheduleFile: base64,
                  scheduleMilestones: analysis
              };
              handleUpdateProject(updated);
          } catch (err) {
              alert("Failed to analyze schedule.");
          } finally {
              setIsAnalyzingSchedule(false);
          }
      };
      reader.readAsDataURL(file);
  };

  const handleSort = (key: string) => {
      let direction: 'asc' | 'desc' = 'asc';
      if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
          direction = 'desc';
      }
      setSortConfig({ key, direction });
  };

  const getProjectValue = (p: ProjectEstimate) => {
      if (p.contractValue) return p.contractValue;
      const mat = p.items.reduce((s, i) => s + (i.quantity * i.unitMaterialCost), 0);
      const lab = p.items.reduce((s, i) => s + (i.quantity * i.unitLaborHours * i.laborRate), 0);
      const sub = mat + lab;
      return sub + (sub * 0.25); 
  };

  const getFollowUpDate = (p: ProjectEstimate) => {
      if (p.followUpDate) return new Date(p.followUpDate);
      if (p.deliveryDate) {
          const d = new Date(p.deliveryDate);
          d.setDate(d.getDate() + 7);
          return d;
      }
      return null;
  };

  const filteredProjects = projects
    .filter(p => {
        if (activeTab === 'ongoing') return p.status === 'Ongoing';
        if (activeTab === 'completed') return p.status === 'Completed';
        if (activeTab === 'estimates') return ['Draft', 'Sent', 'Won', 'Lost', 'Finalized'].includes(p.status);
        return true; 
    })
    .filter(p => 
        p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        p.client.toLowerCase().includes(searchTerm.toLowerCase()) ||
        p.address.toLowerCase().includes(searchTerm.toLowerCase())
    )
    .filter(p => statusFilter === 'All' || p.status === statusFilter)
    .filter(p => clientFilter === 'All' || p.client === clientFilter);

  if (sortConfig) {
      filteredProjects.sort((a, b) => {
          let valA: any = a[sortConfig.key as keyof ProjectEstimate];
          let valB: any = b[sortConfig.key as keyof ProjectEstimate];
          if (sortConfig.key === 'value') {
              valA = getProjectValue(a);
              valB = getProjectValue(b);
          } 
          else if (sortConfig.key === 'timeline') {
              valA = new Date(a.dateCreated).getTime();
              valB = new Date(b.dateCreated).getTime();
          }
          else if (sortConfig.key === 'followUp') {
              const da = getFollowUpDate(a);
              const db = getFollowUpDate(b);
              valA = da ? da.getTime() : 0;
              valB = db ? db.getTime() : 0;
          }
          else if (typeof valA === 'string') {
              valA = valA.toLowerCase();
              valB = valB.toLowerCase();
          }
          if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
          if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
          return 0;
      });
  }

  const handleFilePreview = (project: ProjectEstimate) => {
      setPreviewProject(project);
  };

  const activeChangeOrders = (projectId: string) => tickets.filter(t => t.projectId === projectId);

  const handleClearProjects = () => {
      if (confirm("Are you sure you want to clear the entire Project Database? This cannot be undone.")) {
          setProjects([]);
          alert("Database cleared.");
      }
  };

  return (
    <div className="p-4 md:p-8 max-w-7xl mx-auto space-y-6 h-full flex flex-col">
      {/* ... Header and Filters ... */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 shrink-0">
        <div>
          <h1 className="text-3xl font-bold text-slate-900 tracking-tight flex items-center gap-2">
              {activeTab === 'ongoing' ? 'Project Management' : activeTab === 'completed' ? 'Project Archives' : 'Estimates'}
          </h1>
          <p className="text-slate-500 mt-1">
              {activeTab === 'ongoing' ? 'Track progress, permits, and schedules.' : 'Manage your estimating pipeline.'}
          </p>
        </div>

        <div className="bg-slate-100 p-1 rounded-lg flex overflow-x-auto max-w-full">
            <button onClick={() => {setActiveTab('estimates'); setStatusFilter('All');}} className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'estimates' ? 'bg-white shadow text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}>Estimates</button>
            <button onClick={() => {setActiveTab('ongoing'); setStatusFilter('All');}} className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'ongoing' ? 'bg-white shadow text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}>Ongoing</button>
            <button onClick={() => {setActiveTab('completed'); setStatusFilter('All');}} className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'completed' ? 'bg-white shadow text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}>Completed</button>
            <button onClick={() => {setActiveTab('all'); setStatusFilter('All');}} className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'all' ? 'bg-white shadow text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}>All</button>
        </div>
      </div>

      <div className="flex flex-col md:flex-row gap-4 items-center bg-white p-4 rounded-xl shadow-sm border border-slate-200 shrink-0">
        <div className="relative flex-1 w-full">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input
            type="text"
            placeholder="Search projects, clients, addresses..."
            className="w-full pl-10 pr-4 py-2.5 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex gap-2 w-full md:w-auto overflow-x-auto items-center">
            {activeTab !== 'ongoing' && activeTab !== 'completed' && (
                <select 
                    className="px-3 py-2.5 border border-slate-200 rounded-lg text-sm bg-slate-50 text-slate-700 outline-none focus:border-blue-500 cursor-pointer"
                    value={statusFilter}
                    onChange={(e) => setStatusFilter(e.target.value)}
                >
                    <option value="All">All Statuses</option>
                    {activeTab === 'estimates' || activeTab === 'all' ? (
                        <>
                            <option value="Draft">Draft</option>
                            <option value="Sent">Sent</option>
                            <option value="Won">Won</option>
                            <option value="Lost">Lost</option>
                        </>
                    ) : null}
                    {activeTab === 'all' && (
                        <>
                            <option value="Ongoing">Ongoing</option>
                            <option value="Completed">Completed</option>
                        </>
                    )}
                </select>
            )}

            <select 
                className="px-3 py-2.5 border border-slate-200 rounded-lg text-sm bg-slate-50 text-slate-700 outline-none focus:border-blue-500 cursor-pointer max-w-[150px]"
                value={clientFilter}
                onChange={(e) => setClientFilter(e.target.value)}
            >
                <option value="All">All Clients</option>
                {uniqueClients.map(client => (
                    <option key={client} value={client}>{client}</option>
                ))}
            </select>

            <div className="h-10 w-px bg-slate-200 mx-1 hidden md:block"></div>

            <button 
                onClick={() => setViewMode(viewMode === 'list' ? 'map' : 'list')}
                className={`p-2.5 rounded-lg border transition-colors ${viewMode === 'map' ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-50'}`}
                title="Toggle Map View"
            >
                {viewMode === 'list' ? <MapIcon className="w-5 h-5" /> : <List className="w-5 h-5" />}
            </button>

            <div className="flex items-center gap-1">
                <label className="flex items-center p-2.5 rounded-lg border border-slate-200 bg-white text-slate-500 hover:bg-slate-50 cursor-pointer transition-colors" title="Import Excel">
                    <FileSpreadsheet className="w-5 h-5 text-green-600" />
                    <input type="file" accept=".xlsx, .xls" onChange={handleDbUpload} className="hidden" />
                </label>

                <button 
                    onClick={handleInitSharePoint}
                    className="p-2.5 rounded-lg border border-slate-200 bg-white text-slate-500 hover:bg-slate-50 transition-colors"
                    title="Sync SharePoint"
                >
                    <Globe className="w-5 h-5 text-indigo-600" />
                </button>

                <button 
                    onClick={handleDownloadTemplate}
                    className="p-2.5 rounded-lg border border-slate-200 bg-white text-slate-500 hover:bg-slate-50 transition-colors"
                    title="Download Template"
                >
                    <Download className="w-5 h-5 text-blue-600" />
                </button>

                <button 
                    onClick={handleClearProjects}
                    className="p-2.5 rounded-lg border border-red-200 bg-white text-red-500 hover:bg-red-50 transition-colors"
                    title="Clear Database"
                >
                    <Trash2 className="w-5 h-5" />
                </button>
            </div>

            <button 
                onClick={handleCreateManualProject}
                className="bg-slate-900 text-white px-4 py-2.5 rounded-lg text-sm font-bold hover:bg-slate-800 flex items-center gap-2 shadow-sm whitespace-nowrap"
            >
                <Plus className="w-4 h-4" /> <span className="hidden md:inline">New Project</span>
            </button>
        </div>
      </div>

      {viewMode === 'map' ? (
          <div className="flex-1 min-h-[500px] bg-white rounded-xl shadow-sm border border-slate-200 p-1">
              <ProjectMap projects={filteredProjects} />
          </div>
      ) : (
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 flex-1 overflow-hidden flex flex-col">
            <div className="overflow-x-auto flex-1 custom-scrollbar">
                <table className="w-full text-left text-sm min-w-[1000px]">
                    <thead className="bg-slate-50 border-b border-slate-200 text-slate-500 font-bold uppercase text-xs tracking-wider sticky top-0 z-10">
                        <tr>
                            <th className="px-6 py-4 w-16">Image</th>
                            <th className="px-6 py-4 cursor-pointer hover:bg-slate-100 transition" onClick={() => handleSort('name')}><div className="flex items-center gap-1">Project <ArrowUpDown className="w-3 h-3"/></div></th>
                            <th className="px-6 py-4">Client</th>
                            <th className="px-6 py-4 cursor-pointer hover:bg-slate-100 transition" onClick={() => handleSort('value')}><div className="flex items-center gap-1">Value <ArrowUpDown className="w-3 h-3"/></div></th>
                            <th className="px-6 py-4 text-center">Status</th>
                            <th className="px-6 py-4 w-32">Estimator</th>
                            <th className="px-6 py-4 cursor-pointer hover:bg-slate-100 transition" onClick={() => handleSort('timeline')}><div className="flex items-center gap-1">Timeline <ArrowUpDown className="w-3 h-3"/></div></th>
                            {(activeTab === 'estimates' || activeTab === 'all') && (<th className="px-6 py-4 cursor-pointer hover:bg-slate-100 transition" onClick={() => handleSort('followUp')}><div className="flex items-center gap-1">Follow Up <ArrowUpDown className="w-3 h-3"/></div></th>)}
                            <th className="px-6 py-4 text-center sticky right-0 bg-slate-50">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                        {filteredProjects.map((project) => {
                            const value = getProjectValue(project);
                            const followUp = getFollowUpDate(project);
                            const isUrgent = followUp && new Date() > followUp;
                            const isWonOrLost = project.status === 'Won' || project.status === 'Lost' || project.status === 'Completed';
                            return (
                                <tr key={project.id} className="hover:bg-blue-50/30 transition-colors group">
                                    <td className="px-6 py-3">
                                        <div className="w-12 h-12 rounded-lg bg-slate-100 border border-slate-200 flex items-center justify-center overflow-hidden cursor-pointer hover:ring-2 ring-blue-500 transition relative" onClick={() => setEditingProject(project)}>
                                            {project.projectImage ? <img src={project.projectImage} alt="Project" className="w-full h-full object-cover" onError={(e) => { e.currentTarget.onerror = null; e.currentTarget.src='data:image/svg+xml;base64,'; }} /> : <ImageIcon className="w-5 h-5 text-slate-400" />}
                                        </div>
                                    </td>
                                    <td className="px-6 py-3"><div className="font-semibold text-slate-900">{project.name}</div><div className="text-xs text-slate-500 flex items-center gap-1"><MapPin className="w-3 h-3" />{project.city || 'Miami'}</div></td>
                                    <td className="px-6 py-3"><div className="font-medium text-slate-700">{project.client}</div><div className="text-xs text-slate-400 truncate max-w-[150px]">{project.contactInfo}</div></td>
                                    <td className="px-6 py-3 font-bold text-slate-900 tabular-nums">${value.toLocaleString(undefined, { maximumFractionDigits: 0 })}</td>
                                    <td className="px-6 py-3 text-center">
                                        <select value={project.status} onChange={(e) => handleInlineUpdate(project.id, 'status', e.target.value)} className={`text-xs font-bold px-2 py-1 rounded-full border-none outline-none cursor-pointer appearance-none text-center w-24 ${project.status === 'Won' ? 'bg-emerald-100 text-emerald-700' : project.status === 'Lost' ? 'bg-red-100 text-red-700' : project.status === 'Sent' ? 'bg-blue-100 text-blue-700' : project.status === 'Ongoing' ? 'bg-indigo-100 text-indigo-700' : project.status === 'Completed' ? 'bg-slate-200 text-slate-600' : 'bg-yellow-100 text-yellow-700'}`}>
                                            <option value="Draft">Draft</option><option value="Sent">Sent</option><option value="Won">Won</option><option value="Lost">Lost</option><option value="Ongoing">Ongoing</option><option value="Completed">Completed</option>
                                        </select>
                                    </td>
                                    <td className="px-6 py-3 w-32">
                                        <select value={project.estimator || ''} onChange={(e) => handleInlineUpdate(project.id, 'estimator', e.target.value)} className="text-xs text-slate-600 bg-transparent border-none outline-none cursor-pointer w-full truncate">
                                            <option value="">Unassigned</option>{uniqueEstimators.map(est => <option key={est} value={est}>{est}</option>)}
                                        </select>
                                    </td>
                                    <td className="px-6 py-3">
                                        <div className="flex flex-col gap-1">
                                            <span className="text-xs text-slate-500" title="Created Date">Cr: {new Date(project.dateCreated).toLocaleDateString()}</span>
                                            {project.status === 'Won' && project.awardedDate ? <span className="text-xs font-medium text-emerald-600 bg-emerald-50 px-1.5 py-0.5 rounded w-fit">Won: {new Date(project.awardedDate).toLocaleDateString()}</span> : <><span className="text-xs text-slate-400">Due: {project.deliveryDate ? new Date(project.deliveryDate).toLocaleDateString() : '-'}</span></>}
                                        </div>
                                    </td>
                                    {(activeTab === 'estimates' || activeTab === 'all') && (<td className="px-6 py-3">{!isWonOrLost && followUp ? <div className={`flex items-center gap-1.5 text-xs font-medium ${isUrgent ? 'text-orange-600' : 'text-slate-500'}`}><Clock className="w-3.5 h-3.5" />{followUp.toLocaleDateString()}</div> : <span className="text-xs text-slate-300">-</span>}</td>)}
                                    <td className="px-6 py-3 sticky right-0 bg-white">
                                        <div className="flex items-center justify-center gap-2">
                                            {(project.blueprintImage || project.quantityTableFile) && <button onClick={() => handleFilePreview(project)} className="p-1.5 text-slate-400 hover:text-blue-600 hover:bg-blue-100 rounded transition"><Eye className="w-4 h-4" /></button>}
                                            <button onClick={() => setEditingProject(project)} className="p-1.5 text-slate-400 hover:text-slate-700 hover:bg-slate-200 rounded transition"><Pencil className="w-4 h-4" /></button>
